toolCalls.args:
{"command": "cd /tmp/sv-7eaf12a4eff3441396ac90b79ea1e5cc/symbols

# Try addr2line first (likely won't have line info since stripped, but worth trying)
echo "=== addr2line attempt ==="
for addr in 0x222098 0x222234 0x19bac0 0x19bc14; do
  echo -n "$addr -> "
  aarch64-linux-gnu-addr2line -f -e libmonosgen-2.0.so "$addr" 2>/dev/null || echo "(failed)"
done

# Extract dynamic symbols sorted by address for manual lookup
echo ""
echo "=== Dynamic symbols near our addresses ==="
aarch64-linux-gnu-nm -D --defined-only libmonosgen-2.0.so 2>/dev/null | sort | awk '
{
  addr = strtonum("0x" $1)
  sym[NR] = $0
  addrs[NR] = addr
  names[NR] = $3
  count = NR
}
END {
  # Target addresses
  split("0x222098 0x222234 0x19bac0 0x19bc14", targets, " ")
  for (t in targets) {
    taddr = strtonum(targets[t])
    best = ""
    best_offset = 999999999
    for (i = 1; i <= count; i++) {
      if (addrs[i] <= taddr && (taddr - addrs[i]) < best_offset) {
        best = names[i]
        best_offset = taddr - addrs[i]
        best_addr = addrs[i]
      }
    }
    printf "%s -> %s+0x%x\n", targets[t], best, best_offset
  }
}'", "description": "Symbolicate mono runtime addresses", "initial_wait": 10}
